HTML = "<!doctype html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"UTF-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n    <title>Docker Service Stack</title>\n    <link rel=\"stylesheet\" href=\"/styles.css\" />\n  </head>\n  <body>\n<main class=\"page\">\n  <div class=\"shell\">\n    <header class=\"topbar\">\n      <div class=\"brand\">\n        <span class=\"brand-mark\" aria-hidden=\"true\">U</span>\n        <div class=\"brand-name\">\n          <strong>Docker Service Stack</strong>\n          <span>by Urmate</span>\n        </div>\n      </div>\n      <span class=\"status-pill\">Harbor Stack</span>\n    </header>\n\n    <section class=\"hero\">\n      <div class=\"hero-copy\">\n        <p class=\"eyebrow\">Docker compose starter</p>\n        <h1>A containerized frontend and backend stack.</h1>\n        <p class=\"lead\">A Compose project with an Nginx frontend, Python backend, health route, and production-like wiring.</p>\n        <div class=\"cta-row\">\n          <span class=\"command-chip\">docker compose up</span>\n          <span class=\"mini-chip\">Author: Urmate</span>\n        </div>\n      </div>\n\n      <aside class=\"panel\" aria-label=\"Project snapshot\">\n        <div class=\"panel-head\">\n          <div>\n            <h2>Project snapshot</h2>\n            <p>Starter details for a ready builder workspace.</p>\n          </div>\n          <span class=\"live-dot\" aria-hidden=\"true\"></span>\n        </div>\n\n        <div class=\"metrics\">\n          <div class=\"metric\">\n            <strong>01</strong>\n            <span>Theme system included</span>\n          </div>\n          <div class=\"metric\">\n            <strong>14</strong>\n            <span>Starter and monorepo variants</span>\n          </div>\n          <div class=\"metric\">\n            <strong>100%</strong>\n            <span>Generic project copy</span>\n          </div>\n        </div>\n\n        <div class=\"status-rail\"><span></span></div>\n\n        <div class=\"task-list\">\n          <article class=\"task\">\n            <span class=\"task-index\">1</span>\n            <div>\n              <h3>Interface shell</h3>\n              <p>Responsive layout, metrics, task rows, and service details.</p>\n            </div>\n            <span class=\"task-state\">ready</span>\n          </article>\n          <article class=\"task\">\n            <span class=\"task-index\">2</span>\n            <div>\n              <h3>Theme tokens</h3>\n              <p>Palette, radius, shadow, and motion metadata for Urmate.</p>\n            </div>\n            <span class=\"task-state\">ready</span>\n          </article>\n          <article class=\"task\">\n            <span class=\"task-index\">3</span>\n            <div>\n              <h3>Builder commands</h3>\n              <p>Install, dev, build, and preview commands are documented.</p>\n            </div>\n            <span class=\"task-state\">ready</span>\n          </article>\n        </div>\n      </aside>\n    </section>\n\n    <section class=\"details\" aria-label=\"Template details\">\n      <article class=\"service-card\">\n        <p class=\"eyebrow\">Stack</p>\n        <h2>Ready pieces</h2>\n        <div class=\"stack-row\">\n          <span class=\"stack-chip\">Docker</span>\n              <span class=\"stack-chip\">Nginx</span>\n              <span class=\"stack-chip\">Python</span>\n        </div>\n      </article>\n\n      <article class=\"service-card\">\n        <p class=\"eyebrow\">Service</p>\n        <h2>Local endpoint</h2>\n        <p>The starter keeps the first route visible for quick checks in Builder.</p>\n        <code>/api/health</code>\n      </article>\n    </section>\n  </div>\n</main>\n  </body>\n</html>\n"
CSS = ":root {\n  --bg: #f2fbff;\n  --surface: #ffffff;\n  --ink: #10212b;\n  --muted: #58717d;\n  --primary: #118ab2;\n  --accent: #06d6a0;\n  --secondary: #f9c74f;\n  --line: #cfe9f2;\n  --shadow: 0 24px 66px rgba(17, 138, 178, 0.14);\n  --radius: 12px;\n  color-scheme: light;\n  font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, \"Segoe UI\", sans-serif;\n}\n\n* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  min-width: 320px;\n  background:\n    linear-gradient(120deg, color-mix(in srgb, var(--primary) 10%, transparent), transparent 34%),\n    linear-gradient(150deg, transparent 42%, color-mix(in srgb, var(--accent) 16%, transparent)),\n    var(--bg);\n  color: var(--ink);\n}\n\na {\n  color: inherit;\n}\n\n.page {\n  min-height: 100vh;\n  padding: 28px;\n  position: relative;\n  overflow: hidden;\n}\n\n.page::before {\n  content: \"\";\n  position: fixed;\n  inset: 0;\n  pointer-events: none;\n  background-image:\n    linear-gradient(var(--line) 1px, transparent 1px),\n    linear-gradient(90deg, var(--line) 1px, transparent 1px);\n  background-size: 44px 44px;\n  opacity: 0.32;\n  mask-image: linear-gradient(to bottom, black, transparent 78%);\n}\n\n.shell {\n  width: min(1180px, 100%);\n  margin: 0 auto;\n  position: relative;\n  z-index: 1;\n}\n\n.topbar {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 18px;\n  padding: 14px 0 30px;\n}\n\n.brand {\n  display: inline-flex;\n  align-items: center;\n  gap: 12px;\n  min-width: 0;\n}\n\n.brand-mark {\n  width: 42px;\n  height: 42px;\n  display: grid;\n  place-items: center;\n  border-radius: 12px;\n  background: linear-gradient(135deg, var(--primary), var(--secondary));\n  color: white;\n  font-weight: 800;\n  box-shadow: 0 16px 38px color-mix(in srgb, var(--primary) 28%, transparent);\n}\n\n.brand-name {\n  display: grid;\n  gap: 2px;\n  min-width: 0;\n}\n\n.brand-name strong {\n  font-size: 0.98rem;\n  line-height: 1.1;\n}\n\n.brand-name span,\n.status-pill {\n  color: var(--muted);\n  font-size: 0.86rem;\n}\n\n.status-pill {\n  border: 1px solid var(--line);\n  border-radius: 999px;\n  background: color-mix(in srgb, var(--surface) 86%, transparent);\n  padding: 9px 12px;\n  white-space: nowrap;\n}\n\n.hero {\n  display: grid;\n  grid-template-columns: minmax(0, 1.05fr) minmax(320px, 0.95fr);\n  gap: 24px;\n  align-items: stretch;\n}\n\n.hero-copy,\n.panel,\n.metric,\n.task,\n.service-card {\n  background: color-mix(in srgb, var(--surface) 90%, transparent);\n  border: 1px solid color-mix(in srgb, var(--line) 85%, white);\n  box-shadow: var(--shadow);\n  backdrop-filter: blur(16px);\n}\n\n.hero-copy {\n  border-radius: var(--radius);\n  padding: clamp(28px, 5vw, 58px);\n  display: grid;\n  align-content: center;\n  min-height: 430px;\n}\n\n.eyebrow {\n  margin: 0 0 14px;\n  color: var(--primary);\n  font-weight: 800;\n  font-size: 0.78rem;\n  letter-spacing: 0;\n  text-transform: uppercase;\n}\n\nh1,\nh2,\nh3,\np {\n  margin-top: 0;\n}\n\nh1 {\n  margin-bottom: 18px;\n  max-width: 760px;\n  font-size: clamp(2.55rem, 6vw, 5.35rem);\n  line-height: 0.96;\n  letter-spacing: 0;\n}\n\nh2 {\n  margin-bottom: 14px;\n  font-size: clamp(1.4rem, 3vw, 2.2rem);\n  line-height: 1.05;\n  letter-spacing: 0;\n}\n\nh3 {\n  margin-bottom: 6px;\n  font-size: 1rem;\n}\n\n.lead {\n  max-width: 680px;\n  color: var(--muted);\n  font-size: clamp(1rem, 2vw, 1.18rem);\n  line-height: 1.7;\n}\n\n.cta-row {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 12px;\n  margin-top: 22px;\n}\n\n.command-chip,\n.stack-chip,\n.mini-chip {\n  border: 1px solid var(--line);\n  border-radius: 999px;\n  background: color-mix(in srgb, var(--surface) 84%, transparent);\n  color: var(--ink);\n  padding: 10px 13px;\n  font-size: 0.88rem;\n}\n\n.command-chip {\n  border-color: color-mix(in srgb, var(--primary) 34%, var(--line));\n  color: var(--primary);\n  font-weight: 800;\n}\n\n.panel {\n  border-radius: var(--radius);\n  padding: 22px;\n  overflow: hidden;\n  position: relative;\n}\n\n.panel::before {\n  content: \"\";\n  position: absolute;\n  inset: 0 0 auto;\n  height: 4px;\n  background: linear-gradient(90deg, var(--primary), var(--accent), var(--secondary));\n}\n\n.panel-head {\n  display: flex;\n  justify-content: space-between;\n  gap: 18px;\n  align-items: center;\n  margin-bottom: 18px;\n}\n\n.panel-head p {\n  margin: 0;\n  color: var(--muted);\n  font-size: 0.9rem;\n}\n\n.live-dot {\n  width: 11px;\n  height: 11px;\n  border-radius: 99px;\n  background: var(--accent);\n  box-shadow: 0 0 0 7px color-mix(in srgb, var(--accent) 18%, transparent);\n}\n\n.metrics {\n  display: grid;\n  grid-template-columns: repeat(3, minmax(0, 1fr));\n  gap: 12px;\n  margin-bottom: 18px;\n}\n\n.metric,\n.task,\n.service-card {\n  border-radius: 12px;\n  padding: 16px;\n}\n\n.metric strong {\n  display: block;\n  font-size: clamp(1.4rem, 3vw, 2.1rem);\n  line-height: 1;\n  margin-bottom: 8px;\n}\n\n.metric span,\n.task p,\n.service-card p {\n  color: var(--muted);\n  font-size: 0.9rem;\n  line-height: 1.5;\n}\n\n.task-list {\n  display: grid;\n  gap: 10px;\n}\n\n.task {\n  display: grid;\n  grid-template-columns: auto 1fr auto;\n  gap: 12px;\n  align-items: center;\n  box-shadow: none;\n}\n\n.task-index {\n  width: 32px;\n  height: 32px;\n  display: grid;\n  place-items: center;\n  border-radius: 10px;\n  background: color-mix(in srgb, var(--primary) 12%, white);\n  color: var(--primary);\n  font-weight: 800;\n}\n\n.task-state {\n  color: var(--primary);\n  font-weight: 800;\n  font-size: 0.82rem;\n}\n\n.status-rail {\n  height: 10px;\n  border-radius: 999px;\n  background: color-mix(in srgb, var(--line) 70%, white);\n  overflow: hidden;\n  margin: 18px 0;\n}\n\n.status-rail span {\n  display: block;\n  width: 64%;\n  height: 100%;\n  border-radius: inherit;\n  background: linear-gradient(90deg, var(--primary), var(--accent), var(--secondary));\n}\n\n.stack-row {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 10px;\n}\n\n.details {\n  display: grid;\n  grid-template-columns: 1fr 1fr;\n  gap: 24px;\n  margin-top: 24px;\n  padding-bottom: 28px;\n}\n\n.service-card {\n  box-shadow: none;\n}\n\ncode {\n  display: inline-flex;\n  max-width: 100%;\n  overflow-wrap: anywhere;\n  border-radius: 10px;\n  padding: 8px 10px;\n  background: color-mix(in srgb, var(--ink) 7%, white);\n  color: var(--ink);\n}\n\n@media (prefers-reduced-motion: no-preference) {\n  .hero-copy,\n  .panel,\n  .details > * {\n    animation: rise 520ms ease both;\n  }\n\n  .panel {\n    animation-delay: 80ms;\n  }\n\n  .status-rail span {\n    animation: sweep 4s ease-in-out infinite alternate;\n  }\n\n  .metric,\n  .task,\n  .service-card {\n    transition: transform 180ms ease, box-shadow 180ms ease, border-color 180ms ease;\n  }\n\n  .metric:hover,\n  .task:hover,\n  .service-card:hover {\n    transform: translateY(-3px);\n    border-color: color-mix(in srgb, var(--primary) 36%, var(--line));\n  }\n}\n\n@keyframes rise {\n  from {\n    opacity: 0;\n    transform: translateY(16px);\n  }\n  to {\n    opacity: 1;\n    transform: translateY(0);\n  }\n}\n\n@keyframes sweep {\n  from {\n    width: 36%;\n  }\n  to {\n    width: 88%;\n  }\n}\n\n@media (max-width: 900px) {\n  .page {\n    padding: 18px;\n  }\n\n  .topbar,\n  .panel-head {\n    align-items: flex-start;\n    flex-direction: column;\n  }\n\n  .hero,\n  .details {\n    grid-template-columns: 1fr;\n  }\n\n  .hero-copy {\n    min-height: auto;\n  }\n\n  .metrics {\n    grid-template-columns: 1fr;\n  }\n\n  .task {\n    grid-template-columns: auto 1fr;\n  }\n\n  .task-state {\n    grid-column: 2;\n  }\n}\n"
STARTED_AT = "2026-05-29T00:00:00Z"


class Handler(BaseHTTPRequestHandler):
    def _send(self, status, content_type, body):
        if isinstance(body, str):
            body = body.encode("utf-8")
        self.send_response(status)
        self.send_header("Access-Control-Allow-Origin", "*")
        self.send_header("Content-Type", content_type)
        self.send_header("Content-Length", str(len(body)))
        self.end_headers()
        self.wfile.write(body)

    def do_GET(self):
        if self.path in ("/api/health", "/health"):
            self._send(
                200,
                "application/json",
                json.dumps(
                    {
                        "ok": True,
                        "service": "Docker Service Stack",
                        "author": "Urmate",
                        "theme": "Harbor Stack",
                        "startedAt": STARTED_AT,
                    },
                    indent=2,
                ),
            )
            return

        self._send(
            404,
            "application/json",
            json.dumps({"ok": False, "error": "Route not found", "path": self.path}),
        )


if __name__ == "__main__":
    port = int(os.environ.get("PORT", "8080"))
    server = HTTPServer(("0.0.0.0", port), Handler)
    print("Docker Service Stack listening on http://0.0.0.0:" + str(port))
    server.serve_forever()
